() => {
  const findEarliestSupport = (browserName) => {
    const headers = Array.from(document.querySelectorAll('h4'));
    const header = headers.find(h => h.textContent.trim() === browserName);
    if (!header) return "Not found";

    // The versions are in list items within the same parent or following sibling container
    const container = header.closest('div');
    const supports = container.querySelectorAll('li');

    for (let s of supports) {
      const title = s.getAttribute('title') || s.innerText;
      // 'y' or 'y #n' is full support. CanIUse usually uses 'y' in the class or similar
      // In the snapshot, we see "Supported" text
      if (s.textContent.includes('Supported') && !s.textContent.includes('Partial')) {
        // Extract the version number
        const match = s.textContent.match(/(\d+)/);
        if (match) return match[1];
      }
    }
    return "None";
  };

  const globalUsage = document.querySelector('.feat-usage__total')?.textContent.trim() || 
                      document.querySelector('li[aria-label*="Global usage"]')?.textContent.trim() ||
                      Array.from(document.querySelectorAll('.usage')).find(el => el.textContent.includes('%'))?.textContent.trim();

  const knownIssuesBadge = document.querySelector('button[aria-controls="known-issues"] .badge, .tabs__tab:nth-child(3) .badge, a[href="#known-issues"] .badge');
  const knownIssuesText = Array.from(document.querySelectorAll('.tabs__tab, button')).find(el => el.textContent.includes('Known issues'))?.textContent;
  const knownIssuesCount = knownIssuesText?.match(/\((\d+)\)/)?.[1] || (knownIssuesBadge ? knownIssuesBadge.textContent : "0");

  return {
    globalUsage,
    chrome: findEarliestSupport('Chrome'),
    firefox: findEarliestSupport('Firefox'),
    knownIssues: knownIssuesCount
  };
}

