() => {
  const findEarliestSupport = (browserName) => {
    // Find all h4 elements (browser names)
    const headers = Array.from(document.querySelectorAll('h4'));
    const header = headers.find(h => h.textContent.trim().toLowerCase() === browserName.toLowerCase());
    if (!header) return "Header not found";

    // The versions are in sister divs/sections of the header's parent
    const browserContainer = header.parentElement;
    const versionBlocks = browserContainer.querySelectorAll('.y, .n, .a, .p'); // CanIUse classes for support

    // Alternative: search for children that have the "Supported" text from the accessibility snapshot
    const children = Array.from(browserContainer.querySelectorAll('*'));
    for (let child of children) {
       // Check if it's a version block with full support 'y' or text ": Supported"
       if (child.classList.contains('y') || (child.innerText && child.innerText.includes(': Supported') && !child.innerText.includes('Partial'))) {
         const versionMatch = child.innerText.match(/^(\d+)/);
         if (versionMatch) return versionMatch[1];
       }
    }
    return "Not found";
  };

  const globalTotal = document.querySelector('.feat-usage__total');
  const knownIssuesTab = Array.from(document.querySelectorAll('button, a, .tab')).find(el => el.textContent.includes('Known issues'));

  return {
    chrome: findEarliestSupport('Chrome'),
    firefox: findEarliestSupport('Firefox'),
    usage: globalTotal ? globalTotal.textContent.trim() : "Not found",
    issues: knownIssuesTab ? knownIssuesTab.textContent.trim() : "Not found"
  };
}

