() => {
  const result = {};

  // Usage
  const globalTotal = Array.from(document.querySelectorAll('li, div')).find(el => el.textContent.includes('Total') && el.textContent.includes('%'));
  if (globalTotal) {
    result.globalUsage = globalTotal.textContent.trim().split(' ')[0];
  }

  // Known issues
  const knownIssuesTab = Array.from(document.querySelectorAll('.tablist__tab, button, a')).find(el => el.textContent.includes('Known issues'));
  if (knownIssuesTab) {
    const match = knownIssuesTab.textContent.match(/\((\d+)\)/);
    result.knownIssuesCount = match ? match[1] : "0";
  }

  // Browser support
  const getBrowserStart = (name) => {
    // Find heading with browser name
    const heading = Array.from(document.querySelectorAll('h4')).find(h => h.textContent.trim() === name);
    if (!heading) return "Not found";

    // Browse following siblings or parent's content
    const container = heading.closest('.browser-feature'); // CanIUse's common class for browser columns
    // Check elements with class 'y' (full support)
    const supports = Array.from(document.querySelectorAll('.y'));
    // Filter those within the browser's column. Often they are descendants.
    // Let's use the accessibility tree approach: find the element that says ": Supported" 
    const browserSection = heading.closest('div'); // The block containing the browser name and versions
    const allVersions = Array.from(browserSection.querySelectorAll('li, div, span'));
    for (let el of allVersions) {
       // Check if it's full support. CanIUse typically uses 'y' class. 
       // In the snapshot text, it showed ": Supported"
       if (el.textContent.includes(': Supported') && !el.textContent.includes('Partial')) {
          const v = el.textContent.match(/^(\d+)/);
          if (v) return v[1];
       }
    }
    return "No full support found";
  };

  result.chrome = getBrowserStart('Chrome');
  result.firefox = getBrowserStart('Firefox');

  return result;
}

